const CLASS_ROOM_MAP = {
    'm1': ['ม.1/1', 'ม.1/2', 'ม.1/3'],
    'm2': ['ม.2/1', 'ม.2/2', 'ม.2/3'],
    'm3': ['ม.3/1', 'ม.3/2', 'ม.3/3']
};

// Helper to sync studentRosters and leaderboardDatabase, save to localStorage, and broadcast
function saveAndSyncStudentData() {
    const newRosters = {
        'm3': { '1': [], '2': [], '3': [] },
        'm2': { '1': [], '2': [], '3': [] },
        'm1': { '1': [], '2': [], '3': [] }
    };

    leaderboardDatabase.forEach(student => {
        const cls = student.class;
        let roomNum = '1';
        if (student.room) {
            const match = student.room.match(/\d+$/);
            if (match) roomNum = match[0];
        }

        if (newRosters[cls] && newRosters[cls][roomNum]) {
            newRosters[cls][roomNum].push({
                id: student.studentId || ('stu-gen-' + Math.random().toString(36).substr(2, 9)),
                name: student.name,
                email: student.email || '',
                code: student.studentId || '',
                avatar: student.name.charAt(0),
                loginTime: 'ยังไม่เข้าสู่ระบบ',
                parentPhone: student.phone || '',
                score: student.score || 0
            });
        }
    });

    studentRosters = newRosters;
    localStorage.setItem('lms-student-rosters', JSON.stringify(studentRosters));
    localStorage.setItem('lms-leaderboard-database', JSON.stringify(leaderboardDatabase));

    // Broadcast changes to other dashboard windows
    bc.postMessage({
        type: 'STUDENTS_DATABASE_SYNC',
        leaderboardDatabase,
        studentRosters
    });
}

// --- EXCEL IMPORT FUNCTIONS ---
window.openExcelImportModal = function() {
    document.getElementById('excel-file-input').value = '';
    document.getElementById('excel-file-name').textContent = 'รองรับไฟล์ .xlsx, .xls, .csv ขนาดไม่เกิน 5MB';
    document.getElementById('excel-preview-section').style.display = 'none';
    document.getElementById('excel-preview-table-body').innerHTML = '';

    const btnConfirm = document.getElementById('btn-confirm-excel-import');
    btnConfirm.disabled = true;
    btnConfirm.style.opacity = '0.5';
    btnConfirm.style.cursor = 'not-allowed';

    window.tempParsedStudents = [];
    document.getElementById('excelImportModal').style.display = 'flex';
};

window.closeExcelImportModal = function() {
    document.getElementById('excelImportModal').style.display = 'none';
};

window.handleExcelDrop = function(e) {
    e.preventDefault();
    const files = e.dataTransfer.files;
    if (files.length > 0) {
        processExcelFile(files[0]);
    }
};

window.handleExcelSelect = function(e) {
    const files = e.target.files;
    if (files.length > 0) {
        processExcelFile(files[0]);
    }
};

function processExcelFile(file) {
    const fileNameEl = document.getElementById('excel-file-name');
    if (fileNameEl) fileNameEl.textContent = `ไฟล์ที่เลือก: ${file.name} (${(file.size / 1024).toFixed(1)} KB)`;

    const reader = new FileReader();
    reader.onload = function(e) {
        try {
            const data = new Uint8Array(e.target.result);
            const workbook = XLSX.read(data, { type: 'array' });
            const firstSheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[firstSheetName];

            const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });

            if (rows.length < 2) {
                showToast('ไฟล์ไม่มีข้อมูล', 'ไฟล์ที่อัปโหลดไม่มีข้อมูลรายชื่อนักเรียน หรือมีเพียงหัวข้อคอลัมน์', 'error');
                return;
            }

            parseAndPreviewStudents(rows);
        } catch (err) {
            showToast('เกิดข้อผิดพลาด', 'ไม่สามารถอ่านไฟล์ได้ กรุณาใช้เทมเพลตที่กำหนด: ' + err.message, 'error');
        }
    };
    reader.readAsArrayBuffer(file);
}

function parseAndPreviewStudents(rows) {
    const tbody = document.getElementById('excel-preview-table-body');
    const previewSection = document.getElementById('excel-preview-section');
    const countEl = document.getElementById('excel-preview-count');
    const badge = document.getElementById('excel-validation-badge');
    const btnConfirm = document.getElementById('btn-confirm-excel-import');

    if (!tbody || !previewSection || !countEl || !badge || !btnConfirm) return;

    tbody.innerHTML = '';
    window.tempParsedStudents = [];

    let validCount = 0;
    let invalidCount = 0;

    for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        if (!row || row.length === 0 || (row.length === 1 && !row[0])) continue;

        const rawName = String(row[0] || '').trim();
        const rawCode = String(row[1] || '').trim();
        const rawClass = String(row[2] || '').trim().toLowerCase();
        const rawRoom = String(row[3] || '').trim();
        const rawPhone = String(row[4] || '').trim();

        let errors = [];
        let studentClass = '';
        let studentRoom = '';

        if (!rawName) {
            errors.push('กรุณาระบุชื่อ-นามสกุล');
        }
        if (!rawCode) {
            errors.push('กรุณาระบุรหัสประจำตัว');
        }

        if (!rawClass) {
            errors.push('กรุณาระบุระดับชั้น');
        } else {
            if (rawClass.includes('1') || rawClass.includes('m1') || rawClass.includes('ม.1')) {
                studentClass = 'm1';
            } else if (rawClass.includes('2') || rawClass.includes('m2') || rawClass.includes('ม.2')) {
                studentClass = 'm2';
            } else if (rawClass.includes('3') || rawClass.includes('m3') || rawClass.includes('ม.3')) {
                studentClass = 'm3';
            } else {
                errors.push('ระดับชั้นไม่ถูกต้อง (ระบุ m1, m2, หรือ m3)');
            }
        }

        if (!rawRoom) {
            errors.push('กรุณาระบุห้องเรียน');
        } else {
            const matchNum = rawRoom.match(/[1-3]/);
            if (matchNum) {
                studentRoom = matchNum[0];
            } else {
                errors.push('ห้องเรียนไม่ถูกต้อง (ระบุ 1, 2, หรือ 3)');
            }
        }

        let isDuplicate = false;
        if (rawName && studentRoom) {
            const formattedRoom = `ม.${studentClass === 'm3' ? '3' : studentClass === 'm2' ? '2' : '1'}/${studentRoom}`;
            const dup = leaderboardDatabase.find(s => s.name === rawName && s.room === formattedRoom);
            if (dup) {
                errors.push('ชื่อนักเรียนซ้ำในห้องนี้แล้ว');
            }
        }

        const isValid = errors.length === 0;
        if (isValid) {
            validCount++;
            window.tempParsedStudents.push({
                name: rawName,
                code: rawCode,
                class: studentClass,
                room: `ม.${studentClass === 'm3' ? '3' : studentClass === 'm2' ? '2' : '1'}/${studentRoom}`,
                phone: rawPhone || null
            });
        } else {
            invalidCount++;
        }

        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border)';
        tr.style.background = isValid ? 'var(--white)' : 'rgba(239, 68, 68, 0.02)';

        const statusBadge = isValid 
            ? '<span style="background: var(--success-bg); color: var(--success-text); padding: 2px 8px; border-radius: 12px; font-size: 0.72rem; font-weight: 600;">ผ่าน</span>' 
            : `<span style="background: var(--danger-bg); color: var(--danger-text); padding: 2px 8px; border-radius: 12px; font-size: 0.72rem; font-weight: 600; display: inline-block; cursor: help;" title="${errors.join(', ')}">ไม่ผ่าน (${errors.length})</span>`;

        tr.innerHTML = `
            <td style="padding: 8px 12px; color: var(--text-muted);">${i}</td>
            <td style="padding: 8px 12px; font-weight: 600; color: var(--text-main);">${rawName || '-'}</td>
            <td style="padding: 8px 12px; font-family: monospace; color: var(--text-main);">${rawCode || '-'}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${studentClass ? (studentClass === 'm3' ? 'ม.3' : studentClass === 'm2' ? 'ม.2' : 'ม.1') : (rawClass || '-')}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${studentRoom ? 'ห้อง ' + studentRoom : (rawRoom || '-')}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${rawPhone || '-'}</td>
            <td style="padding: 8px 12px;">${statusBadge}</td>
        `;
        tbody.appendChild(tr);
    }

    countEl.textContent = rows.length - 1;
    previewSection.style.display = 'flex';

    if (validCount > 0) {
        badge.style.background = 'var(--success-bg)';
        badge.style.color = 'var(--success-text)';
        badge.textContent = `ตรวจสอบสำเร็จ (ผ่าน ${validCount} / ไม่ผ่าน ${invalidCount})`;

        btnConfirm.disabled = false;
        btnConfirm.style.opacity = '1';
        btnConfirm.style.cursor = 'pointer';
    } else {
        badge.style.background = 'var(--danger-bg)';
        badge.style.color = 'var(--danger-text)';
        badge.textContent = 'ไม่พบข้อมูลที่ผ่านเกณฑ์การตรวจสอบ';

        btnConfirm.disabled = true;
        btnConfirm.style.opacity = '0.5';
        btnConfirm.style.cursor = 'not-allowed';
    }
}

window.confirmExcelImport = function() {
    if (!window.tempParsedStudents || window.tempParsedStudents.length === 0) return;

    const importedCount = window.tempParsedStudents.length;

    window.tempParsedStudents.forEach(student => {
        leaderboardDatabase.push({
            name: student.name,
            score: 1000,
            class: student.class,
            room: student.room,
            studentId: student.code,
            nickname: null,
            gender: null,
            studentNumber: null,
            phone: student.phone || null,
            email: null
        });
    });

    saveAndSyncStudentData();
    closeExcelImportModal();
    renderStudentList();
    updateClassLeaderboardUI();
    updateStudentStatCards();

    showToast('นำเข้าสำเร็จ', `นำเข้ารายชื่อนักเรียนจำนวน ${importedCount} คน เรียบร้อยแล้ว`, 'success');
};

window.downloadStudentImportTemplate = function() {
    const headers = [["ชื่อ-นามสกุล", "รหัสนักเรียน", "ระดับชั้น (m1/m2/m3)", "ห้องเรียน (1/2/3)", "เบอร์โทรผู้ปกครอง"]];
    const sampleData = [
        ["นายสมชาย รักเรียน", "660104", "m3", "1", "0812345678"],
        ["นางสาวสมหญิง รักดี", "660105", "m3", "1", "0898765432"],
        ["เด็กชายเดชา เก่งกล้า", "670104", "m2", "1", "0855551234"]
    ];

    const wsData = headers.concat(sampleData);
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(wsData);

    ws['!cols'] = [
        { wch: 25 }, 
        { wch: 15 }, 
        { wch: 22 }, 
        { wch: 18 }, 
        { wch: 20 }  
    ];

    XLSX.utils.book_append_sheet(wb, ws, "รายชื่อนักเรียน");
    XLSX.writeFile(wb, "Template_Import_Students.xlsx");
    showToast('สำเร็จ', 'ดาวน์โหลดไฟล์เทมเพลต Excel เรียบร้อยแล้ว', 'success');
};

function openAddStudentModal() {
    const nextId = 'STU-' + String(leaderboardDatabase.length + 1).padStart(3, '0');
    const displayEl = document.getElementById('modal-student-id-display');
    if (displayEl) displayEl.textContent = nextId;

    document.getElementById('modal-student-name').value = '';
    document.getElementById('modal-student-nickname').value = '';
    document.getElementById('modal-student-gender').value = '';
    document.getElementById('modal-student-class').value = '';
    document.getElementById('modal-student-room').innerHTML = '<option value="">-- ห้อง --</option>';
    document.getElementById('modal-student-number').value = '';
    document.getElementById('modal-student-phone').value = '';
    document.getElementById('modal-student-email').value = '';

    document.getElementById('studentModal').style.display = 'flex';
}

function closeStudentModal() {
    document.getElementById('studentModal').style.display = 'none';
}

function populateRoomSelect(selectEl, classVal, selectedRoom) {
    selectEl.innerHTML = '<option value="">-- เลือกห้อง --</option>';
    if (CLASS_ROOM_MAP[classVal]) {
        CLASS_ROOM_MAP[classVal].forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            if (room === selectedRoom) opt.selected = true;
            selectEl.appendChild(opt);
        });
    }
}

function updateModalRoomOptions() {
    const classVal = document.getElementById('modal-student-class').value;
    const roomSelect = document.getElementById('modal-student-room');
    populateRoomSelect(roomSelect, classVal, '');
}

function updateEditStudentRoomOptions() {
    const classVal = document.getElementById('edit-student-class').value;
    const roomSelect = document.getElementById('edit-student-room');
    populateRoomSelect(roomSelect, classVal, '');
}

function updateRoomFilterOptions() {
    const classFilter = document.getElementById('student-list-filter-class');
    const roomFilter = document.getElementById('student-list-filter-room');
    if (!roomFilter) return;
    const classVal = classFilter ? classFilter.value : 'all';
    roomFilter.innerHTML = '<option value="all">ทุกห้อง</option>';
    if (classVal !== 'all' && CLASS_ROOM_MAP[classVal]) {
        CLASS_ROOM_MAP[classVal].forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            roomFilter.appendChild(opt);
        });
    } else if (classVal === 'all') {
        const allRooms = new Set();
        leaderboardDatabase.forEach(s => allRooms.add(s.room));
        [...allRooms].sort().forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            roomFilter.appendChild(opt);
        });
    }
}

function saveStudentFromModal() {
    const name = document.getElementById('modal-student-name').value.trim();
    const nickname = document.getElementById('modal-student-nickname').value.trim();
    const gender = document.getElementById('modal-student-gender').value;
    const classVal = document.getElementById('modal-student-class').value;
    const room = document.getElementById('modal-student-room').value;
    const studentNumber = document.getElementById('modal-student-number').value;
    const phone = document.getElementById('modal-student-phone').value.trim();
    const email = document.getElementById('modal-student-email').value.trim();
    const studentId = document.getElementById('modal-student-id-display').textContent;

    if (!name) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาระบุชื่อ-นามสกุลของนักเรียน', 'error');
        return;
    }
    if (!classVal) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาเลือกระดับชั้นของนักเรียน', 'error');
        return;
    }
    if (!room) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาเลือกห้องของนักเรียน', 'error');
        return;
    }

    const exists = leaderboardDatabase.find(s => s.name === name && s.room === room);
    if (exists) {
        showToast('ข้อมูลซ้ำ', `"${name}" มีอยู่ในห้อง ${room} แล้ว`, 'error');
        return;
    }

    leaderboardDatabase.push({
        name,
        score: 1000,
        class: classVal,
        room,
        studentId: studentId || null,
        nickname: nickname || null,
        gender: gender || null,
        studentNumber: studentNumber ? parseInt(studentNumber) : null,
        phone: phone || null,
        email: email || null
    });

    saveAndSyncStudentData();
    closeStudentModal();
    renderStudentList();
    updateClassLeaderboardUI();
    updateStudentStatCards();

    showToast('เพิ่มสำเร็จ', `เพิ่ม "${name}" เข้าสู่ห้อง ${room} เรียบร้อยแล้ว`, 'success');
}

function updateStudentStatCards() {
    const m1 = leaderboardDatabase.filter(s => s.class === 'm1').length;
    const m2 = leaderboardDatabase.filter(s => s.class === 'm2').length;
    const m3 = leaderboardDatabase.filter(s => s.class === 'm3').length;
    const all = leaderboardDatabase.length;

    const el1 = document.getElementById('stat-m1-count'); if (el1) el1.textContent = m1;
    const el2 = document.getElementById('stat-m2-count'); if (el2) el2.textContent = m2;
    const el3 = document.getElementById('stat-m3-count'); if (el3) el3.textContent = m3;
    const el4 = document.getElementById('stat-all-count'); if (el4) el4.textContent = all;

    const totalEl = document.getElementById('student-total-count');
    if (totalEl) totalEl.textContent = `ทั้งหมด ${all} คน`;

    const attStatEl = document.getElementById('class-attendance-stat');
    if (attStatEl) attStatEl.innerText = `${all} คน`;
}

function renderStudentList() {
    const container = document.getElementById('student-list-container');
    const emptyState = document.getElementById('student-list-empty');
    const filterClass = document.getElementById('student-list-filter-class');
    const filterRoom = document.getElementById('student-list-filter-room');
    const searchInput = document.getElementById('student-search-input');

    if (!container) return;

    updateRoomFilterOptions();

    const classFilter = filterClass ? filterClass.value : 'all';
    const roomFilter = filterRoom ? filterRoom.value : 'all';
    const searchTerm = searchInput ? searchInput.value.trim().toLowerCase() : '';

    let filtered = [...leaderboardDatabase];

    if (classFilter !== 'all') {
        filtered = filtered.filter(s => s.class === classFilter);
    }
    if (roomFilter !== 'all') {
        filtered = filtered.filter(s => s.room === roomFilter);
    }
    if (searchTerm) {
        filtered = filtered.filter(s =>
            s.name.toLowerCase().includes(searchTerm) ||
            (s.nickname && s.nickname.toLowerCase().includes(searchTerm)) ||
            (s.studentId && s.studentId.toLowerCase().includes(searchTerm))
        );
    }

    updateStudentStatCards();

    if (filtered.length === 0) {
        container.innerHTML = '';
        if (emptyState) emptyState.style.display = 'block';
        return;
    }
    if (emptyState) emptyState.style.display = 'none';

    filtered.sort((a, b) => {
        if (a.room < b.room) return -1;
        if (a.room > b.room) return 1;
        if (a.studentNumber && b.studentNumber) return a.studentNumber - b.studentNumber;
        return b.score - a.score;
    });

    let html = '';
    filtered.forEach((student) => {
        const idx = leaderboardDatabase.indexOf(student);
        const classBadgeColor = student.class === 'm3' ? 'var(--primary)' :
                                student.class === 'm2' ? 'var(--purple-text)' : 'var(--success-text)';
        const classBadgeBg = student.class === 'm3' ? 'var(--primary-light)' :
                             student.class === 'm2' ? 'var(--purple-bg)' : 'var(--success-bg)';
        const classLabel = student.class === 'm3' ? 'ม.3' :
                           student.class === 'm2' ? 'ม.2' : 'ม.1';
        const genderIcon = student.gender === 'male' ? '<i class="fa-solid fa-mars" style="color: #3b82f6; font-size: 0.75rem;"></i>' :
                           student.gender === 'female' ? '<i class="fa-solid fa-venus" style="color: #ec4899; font-size: 0.75rem;"></i>' : '';
        const avatarBg = student.gender === 'female' ? 'linear-gradient(135deg, #fce7f3, #fbcfe8)' :
                         student.gender === 'male' ? `linear-gradient(135deg, ${classBadgeBg}, rgba(59,130,246,0.1))` :
                         `linear-gradient(135deg, ${classBadgeBg}, rgba(14,165,233,0.1))`;
        const avatarColor = student.gender === 'female' ? '#db2777' : classBadgeColor;

        let infoParts = [];
        if (student.studentNumber) infoParts.push(`เลขที่ ${student.studentNumber}`);
        if (student.studentId) infoParts.push(`รหัส: ${student.studentId}`);
        infoParts.push(student.room);
        if (student.nickname) infoParts.push(`"${student.nickname}"`);

        let contactParts = [];
        if (student.phone) contactParts.push(`<i class="fa-solid fa-phone" style="font-size:0.65rem;"></i> ${student.phone}`);
        if (student.email) contactParts.push(`<i class="fa-solid fa-envelope" style="font-size:0.65rem;"></i> ${student.email}`);

        html += `
            <div class="student-row" style="display: flex; align-items: center; justify-content: space-between; padding: 14px 18px; background: var(--white); border: 1px solid var(--border); border-radius: 12px; transition: all 0.2s; gap: 12px;" onmouseover="this.style.borderColor='var(--primary)'; this.style.boxShadow='0 2px 8px rgba(14,165,233,0.08)'" onmouseout="this.style.borderColor='var(--border)'; this.style.boxShadow='none'">
                <div style="display: flex; align-items: center; gap: 14px; flex: 1; min-width: 0;">
                    <div style="width: 40px; height: 40px; border-radius: 50%; background: ${avatarBg}; display: flex; align-items: center; justify-content: center; font-weight: 700; font-size: 0.88rem; color: ${avatarColor}; flex-shrink: 0; position: relative;">
                        ${student.name.charAt(0)}
                        ${genderIcon ? `<span style="position:absolute; bottom:-2px; right:-2px; background:var(--white); border-radius:50%; width:16px; height:16px; display:flex; align-items:center; justify-content:center; border:1px solid var(--border);">${genderIcon}</span>` : ''}
                    </div>
                    <div style="min-width: 0; flex: 1;">
                        <div style="display: flex; align-items: center; gap: 8px; flex-wrap: wrap;">
                            <span style="font-weight: 600; font-size: 0.92rem; color: var(--text-main);">${student.name}</span>
                            <span style="padding: 2px 8px; border-radius: 6px; font-size: 0.72rem; font-weight: 600; background: ${classBadgeBg}; color: ${classBadgeColor};">${classLabel}</span>
                        </div>
                        <div style="font-size: 0.76rem; color: var(--text-muted); margin-top: 3px;">${infoParts.join(' · ')}</div>
                        ${contactParts.length > 0 ? `<div style="font-size: 0.72rem; color: var(--text-muted); margin-top: 2px; display: flex; gap: 12px; flex-wrap: wrap;">${contactParts.join(' ')}</div>` : ''}
                    </div>
                </div>
                <div style="display: flex; align-items: center; gap: 8px; flex-shrink: 0;">
                    <span style="font-size: 0.85rem; font-weight: 700; color: var(--text-main); font-family: 'Outfit', 'Prompt', sans-serif; min-width: 65px; text-align: right;">${student.score.toLocaleString()} pts</span>
                    <button onclick="openEditStudentModal(${idx})" style="width: 32px; height: 32px; border-radius: 8px; border: 1px solid rgba(14,165,233,0.2); background: var(--primary-light); color: var(--primary); cursor: pointer; display: flex; align-items: center; justify-content: center; transition: all 0.2s; flex-shrink: 0;" title="แก้ไขข้อมูล" onmouseover="this.style.transform='scale(1.1)'" onmouseout="this.style.transform='scale(1)'">
