    document.getElementById('modal-student-email').value = '';

    document.getElementById('studentModal').style.display = 'flex';
}

function closeStudentModal() {
    document.getElementById('studentModal').style.display = 'none';
}

function populateRoomSelect(selectEl, classVal, selectedRoom) {
    selectEl.innerHTML = '<option value="">-- เลือกห้อง --</option>';
    if (CLASS_ROOM_MAP[classVal]) {
        CLASS_ROOM_MAP[classVal].forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            if (room === selectedRoom) opt.selected = true;
            selectEl.appendChild(opt);
        });
    }
}

function updateModalRoomOptions() {
    const classVal = document.getElementById('modal-student-class').value;
    const roomSelect = document.getElementById('modal-student-room');
    populateRoomSelect(roomSelect, classVal, '');
}

function updateEditStudentRoomOptions() {
    const classVal = document.getElementById('edit-student-class').value;
    const roomSelect = document.getElementById('edit-student-room');
    populateRoomSelect(roomSelect, classVal, '');
}

function updateRoomFilterOptions() {
    const classFilter = document.getElementById('student-list-filter-class');
    const roomFilter = document.getElementById('student-list-filter-room');
    if (!roomFilter) return;
    const classVal = classFilter ? classFilter.value : 'all';
    roomFilter.innerHTML = '<option value="all">ทุกห้อง</option>';
    if (classVal !== 'all' && CLASS_ROOM_MAP[classVal]) {
        CLASS_ROOM_MAP[classVal].forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            roomFilter.appendChild(opt);
        });
    } else if (classVal === 'all') {
        // Show all rooms from all classes
        const allRooms = new Set();
        leaderboardDatabase.forEach(s => allRooms.add(s.room));
        [...allRooms].sort().forEach(room => {
            const opt = document.createElement('option');
            opt.value = room;
            opt.textContent = room;
            roomFilter.appendChild(opt);
        });
    }
}

