function renderStudentList() {
    const container = document.getElementById('student-list-container');
    const emptyState = document.getElementById('student-list-empty');
    const filterClass = document.getElementById('student-list-filter-class');
    const filterRoom = document.getElementById('student-list-filter-room');
    const searchInput = document.getElementById('student-search-input');

    if (!container) return;

    // Update room filter dropdown
    updateRoomFilterOptions();

    const classFilter = filterClass ? filterClass.value : 'all';
    const roomFilter = filterRoom ? filterRoom.value : 'all';
    const searchTerm = searchInput ? searchInput.value.trim().toLowerCase() : '';

    let filtered = [...leaderboardDatabase];

    if (classFilter !== 'all') {
        filtered = filtered.filter(s => s.class === classFilter);
    }
    if (roomFilter !== 'all') {
        filtered = filtered.filter(s => s.room === roomFilter);
    }
    if (searchTerm) {
        filtered = filtered.filter(s =>
            s.name.toLowerCase().includes(searchTerm) ||
            (s.nickname && s.nickname.toLowerCase().includes(searchTerm)) ||
            (s.studentId && s.studentId.toLowerCase().includes(searchTerm))
        );
    }

    updateStudentStatCards();

